        .insert({ image: 'octocat.png' })
        .insert('\n', { align: 'right' })
        .insert('!');
      delta.eachLine(spy);
      expect(spy.calls.count()).toEqual(4);
      expect(spy.calls.argsFor(0)).toEqual([
        new Delta().insert('Hello'),
        {},
